//-------------------------------------------------------------------------
// 조회 : 데이터를 조회한다.
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
  gr_master.initGrid();
  scwin.f_Setting();
  dma_search.set("fromDate", scwin.fromDate);
  dma_search.set("closeYm", ed_srchCloseYm.getValue());
  dma_search.set("ver", lc_version.getValue());
  dma_search.set("bookClsCd", lc_srchBookClsCd.getValue());
  dma_search.set("acctDeptCd", "1");
  dma_search.set("eisAcctDeptCd", "1");
  dma_search.set("distYn", scwin.tDist);
  $c.sbm.execute($p, sbm_master);
};

//-------------------------------------------------------------------------
// 날짜셋팅 
//-------------------------------------------------------------------------
scwin.f_Setting = function () {
  scwin.imsi_date = ed_srchCloseYm.getValue() + "01";

  // 전년도 구하기
  if (scwin.imsi_date.substring(4, 6) == "01" || scwin.imsi_date.substring(4, 6) == "00") {
    dma_search.set("befCloseYm", scwin.imsi_date.substring(0, 4) + "00");
  } else {
    scwin.pre_yyyymmdd = $c.date.addMonth($p, scwin.imsi_date, -12); // 전년
    dma_search.set("befCloseYm", scwin.pre_yyyymmdd.substring(0, 4) + "00");
  }
  scwin.preBef_yyyymmdd = $c.date.addMonth($p, scwin.imsi_date, -1); // 전월
  dma_search.set("preCloseYm", scwin.preBef_yyyymmdd.substring(0, 6));
  scwin.imsi_date1 = dma_search.get("preCloseYm") + "01";
  if (scwin.preBef_yyyymmdd.substring(4, 6) == "01" || scwin.preBef_yyyymmdd.substring(4, 6) == "00") {
    dma_search.set("preBefCloseYm", scwin.preBef_yyyymmdd.substring(0, 4) + "00");
  } else {
    dma_search.set("preBefCloseYm", scwin.preBef_yyyymmdd.substring(0, 6));
  }
};
//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.ondataload = function () {
  scwin.f_SetDefaultUnit();
};

//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.f_SetDefaultUnit = function () {
  var rcnt = dlt_commonCodeCO012.getRowCount();
  if (rcnt < 1) return;
  var index = 0;
  for (i = 0; i < rcnt; i++) {
    if (dlt_commonCodeCO012.getCellData(i, "fltrCd1") == DGlobalValue.TRUE) {
      index = i;
      break;
    }
  }
  lc_unit.setSelectedIndex(index);
  lc_unit.setSelectedIndex(2);
};

//-------------------------------------------------------------------------
// 버전정보를 구한다.
//-------------------------------------------------------------------------
scwin.f_GetVersion = function () {
  dma_version.set("sysCd", "CommonEBC");
  dma_version.set("queryId", "retrieveVersionInfo");
  dma_version.set("param1", ed_srchCloseYm.getValue().substr(0, 4) + "00");
  $c.sbm.execute($p, sbm_version);
};

