scwin.f_SetGridUnit = function (e) {
  console.log("f_SetGridUnit");
  scwin.sellAmt1 = 0;
  scwin.sellAmt2 = 0;
  scwin.sellAmt3 = 0;
  scwin.sellAmt4 = 0;
  scwin.sellAmt5 = 0;
  scwin.sellAmt6 = 0;
  scwin.sellAmt7 = 0;
  scwin.sellAmt8 = 0;
  scwin.sellAmt9 = 0;
  scwin.sellAmt10 = 0;
  scwin.sellAmt11 = 0;
  scwin.mAcctcd = "";
  scwin.cunit = 1;
  if (lc_unit.getValue() == "02") {
    scwin.cunit = 1000;
  }
  if (lc_unit.getValue() == "03") {
    scwin.cunit = 1000000;
  }
  if (lc_unit.getValue() == "04") {
    scwin.cunit = 100000000;
  }
  scwin.ds_master_rcnt = ds_master.getRowCount();
  for (scwin.i = 0; scwin.i <= scwin.ds_master_rcnt; scwin.i++) {
    scwin.mAcctcd = ds_master.getCellData(scwin.i, "mgntAcctCd");
    //        console.log(scwin.i+" : mgntAcctCdNm - "+ ds_master.getCellData(scwin.i, "mgntAcctCd")+"/"+ds_master.getCellData(scwin.i, "mgntAcctCdNm"));
    scwin.sellAmt1 = $c.num.parseInt($p, ds_master.getCellData(scwin.i, "yearPlanAmt"));
    scwin.sellAmt2 = $c.num.parseInt($p, ds_master.getCellData(scwin.i, "bfyyThisAmt"));
    scwin.sellAmt3 = $c.num.parseInt($p, ds_master.getCellData(scwin.i, "thisPlanAmt"));
    scwin.sellAmt4 = $c.num.parseInt($p, ds_master.getCellData(scwin.i, "thisRsltsAmt"));
    scwin.sellAmt5 = $c.num.parseInt($p, ds_master.getCellData(scwin.i, "befDiffer"));
    scwin.sellAmt6 = $c.num.parseInt($p, ds_master.getCellData(scwin.i, "thisDiffer"));
    scwin.sellAmt7 = $c.num.parseInt($p, ds_master.getCellData(scwin.i, "sumBfyyThisAmt"));
    scwin.sellAmt8 = $c.num.parseInt($p, ds_master.getCellData(scwin.i, "sumPlanAmt"));
    scwin.sellAmt9 = $c.num.parseInt($p, ds_master.getCellData(scwin.i, "sumRsltsAmt"));
    scwin.sellAmt10 = $c.num.parseInt($p, ds_master.getCellData(scwin.i, "sumBefDiffer"));
    scwin.sellAmt11 = $c.num.parseInt($p, ds_master.getCellData(scwin.i, "sumDiffer"));
    if (scwin.mAcctcd == "9300001" || scwin.mAcctcd == "9300002" || scwin.mAcctcd == "9300003" || scwin.mAcctcd == "9300004" || scwin.mAcctcd == "9300005" || scwin.mAcctcd == "9300006") {
      // 당월증감
      ds_master.setCellData(scwin.i, "befDiffer", scwin.sellAmt4 - scwin.sellAmt2); // thisRsltsAmt - bfyyThisAmt
      ds_master.setCellData(scwin.i, "thisDiffer", scwin.sellAmt4 - scwin.sellAmt3); // thisRsltsAmt - thisPlanAmt
      // 누계증감
      ds_master.setCellData(scwin.i, "sumBefDiffer", scwin.sellAmt9 - scwin.sellAmt7); // sumRsltsAmt - sumBfyyThisAmt
      ds_master.setCellData(scwin.i, "sumDiffer", scwin.sellAmt9 - scwin.sellAmt8); //  sumRsltsAmt - sumPlanAmt
    } else {
      try {
        if (isNaN(scwin.sellAmt1)) {
          ds_master.setCellData(scwin.i, "yearPlanAmt", 0);
        } else {
          ds_master.setCellData(scwin.i, "yearPlanAmt", $c.num.round($p, scwin.sellAmt1 / scwin.cunit, 0));
        }
      } catch (e) {
        ds_master.setCellData(scwin.i, "yearPlanAmt", 0);
      }
      ;
      try {
        if (isNaN(scwin.sellAmt2)) {
          ds_master.setCellData(scwin.i, "bfyyThisAmt", 0);
        } else {
          ds_master.setCellData(scwin.i, "bfyyThisAmt", $c.num.round($p, scwin.sellAmt2 / scwin.cunit, 0));
        }
      } catch (e) {
        ds_master.setCellData(scwin.i, "bfyyThisAmt", 0);
      }
      ;
      try {
        if (isNaN(scwin.sellAmt3)) {
          ds_master.setCellData(scwin.i, "thisPlanAmt", 0);
        } else {
          ds_master.setCellData(scwin.i, "thisPlanAmt", $c.num.round($p, scwin.sellAmt3 / scwin.cunit, 0));
        }
      } catch (e) {
        ds_master.setCellData(scwin.i, "thisPlanAmt", 0);
      }
      ;
      try {
        if (isNaN(scwin.sellAmt4)) {
          ds_master.setCellData(scwin.i, "thisRsltsAmt", 0);
        } else {
          ds_master.setCellData(scwin.i, "thisRsltsAmt", $c.num.round($p, scwin.sellAmt4 / scwin.cunit, 0));
        }
      } catch (e) {
        ds_master.setCellData(scwin.i, "thisRsltsAmt", 0);
      }
      ;
      try {
        if (isNaN(scwin.sellAmt7)) {
          ds_master.setCellData(scwin.i, "sumBfyyThisAmt", 0);
        } else {
          ds_master.setCellData(scwin.i, "sumBfyyThisAmt", $c.num.round($p, scwin.sellAmt7 / scwin.cunit, 0));
        }
      } catch (e) {
        ds_master.setCellData(scwin.i, "sumBfyyThisAmt", 0);
      }
      ;
      try {
        if (isNaN(scwin.sellAmt8)) {
          ds_master.setCellData(scwin.i, "sumPlanAmt", 0);
        } else {
          ds_master.setCellData(scwin.i, "sumPlanAmt", $c.num.round($p, scwin.sellAmt8 / scwin.cunit, 0));
        }
      } catch (e) {
        ds_master.setCellData(scwin.i, "sumPlanAmt", 0);
      }
      ;
      try {
        if (isNaN(scwin.sellAmt9)) {
          ds_master.setCellData(scwin.i, "sumRsltsAmt", 0);
        } else {
          ds_master.setCellData(scwin.i, "sumRsltsAmt", $c.num.round($p, scwin.sellAmt9 / scwin.cunit, 0));
        }
      } catch (e) {
        ds_master.setCellData(scwin.i, "sumRsltsAmt", 0);
      }
      ;
      // 당월증감
      ds_master.setCellData(scwin.i, "befDiffer", $c.num.round($p, scwin.sellAmt4 / scwin.cunit, 0) - $c.num.round($p, scwin.sellAmt2 / scwin.cunit, 0)); // thisRsltsAmt - bfyyThisAmt
      ds_master.setCellData(scwin.i, "thisDiffer", $c.num.round($p, scwin.sellAmt4 / scwin.cunit, 0) - $c.num.round($p, scwin.sellAmt3 / scwin.cunit, 0)); // thisRsltsAmt - thisPlanAmt
      // 누계증감
      ds_master.setCellData(scwin.i, "sumBefDiffer", $c.num.round($p, scwin.sellAmt9 / scwin.cunit, 0) - $c.num.round($p, scwin.sellAmt7 / scwin.cunit, 0)); // sumRsltsAmt - sumBfyyThisAmt
      ds_master.setCellData(scwin.i, "sumDiffer", $c.num.round($p, scwin.sellAmt9 / scwin.cunit, 0) - $c.num.round($p, scwin.sellAmt8 / scwin.cunit, 0)); // sumRsltsAmt - sumPlanAmt
    }
  }
};

